  method: 'GET',
  hostname: '127.0.0.1',
  port: '3000',
  path: '/api/enterprise/%7BorganizationId%7D/authentication/%7Bid%7D',
  headers: {
    Authorization: 'Bearer REPLACE_BEARER_TOKEN'
  }
};

